// ════════════════════════════════════════════════════════════════════════
// EVALUATE RECONSTRUCTION — V2
// FIX-5: Pairing via relational_id (bukan posisi array).
// ════════════════════════════════════════════════════════════════════════

const SIMILARITY_HIGH     = 0.95;
const SIMILARITY_MODERATE = 0.70;

// FIX-5: Bangun lookup map dari Validate Embedding
const validatedItems = $('Embedding Quality Validator').all();
const validatedMap = {};
for (const v of validatedItems) {
  const rid = v.json.relational_id;
  if (rid) validatedMap[rid] = v.json;
}

const items = $input.all();

return items.map((item, index) => {
  const recon = item.json;

  // FIX-5: Coba pairing via source_url + chunk_index sebagai composite key,
  // atau relational_id jika tersedia di output Reconstruction Test.
  const rid = recon.relational_id;
  const chunkData = (rid && validatedMap[rid])
    ? validatedMap[rid]
    : (validatedItems[index]?.json || {});

  const sameSim = recon.same_doc_top_sim !== null
    ? Math.round(parseFloat(recon.same_doc_top_sim) * 10_000) / 10_000
    : null;

  let reconstructionNote = 'new_chunk';
  if (sameSim !== null) {
    if (sameSim >= SIMILARITY_HIGH)          reconstructionNote = 'high_similarity_match';
    else if (sameSim >= SIMILARITY_MODERATE) reconstructionNote = 'moderate_similarity_match';
  }

  const rawSuspects = recon.duplicate_suspects;
  const neighborFlags = Array.isArray(rawSuspects)
    ? rawSuspects.filter(Boolean).map(d => `DUPLICATE_SUSPECT: ${d}`)
    : [];

  return {
    json: {
      ...chunkData,
      _rt_similarity:     sameSim,
      _rt_note:           reconstructionNote,
      _rt_neighbor_flags: neighborFlags,
    },
  };
});

const input      = $input.first().json;
const errorMsg   = input.error?.message || input.message || 'Unknown LLM error';
const executionId = $execution?.id || 'unknown-execution';

return [{
  json: {
    error_source:    'LLM_NODE',
    error_message:   errorMsg,
    execution_id:    executionId,
    source_url:      input.source_url || input.url || null,
    doc_number:      input.doc_number || null,
    failed_at:       new Date().toISOString(),
    retry_suggested: true,
  },
}];

