const TYPE_MAP = {
  pmk: 'PMK', uu: 'UU', pp: 'PP',
  per: 'PER', kmk: 'KMK', se: 'SE',
};

const SLUG_RE = /^([a-z]+)-(\d+)(?:[a-z0-9\-]*?)-tahun-(\d{4})$/;

const input  = $input.first().json;
const gSheet = $('Google Sheets Trigger').first().json;

const rawUrl = input['Url'] || '';
if (!rawUrl.trim()) {
  throw new Error('[ParseJDIHURL] Field "Url" kosong atau tidak ditemukan di row Google Sheet.');
}

const resolvedSourceUrl = gSheet.PDF || gSheet.Url || '';
if (!resolvedSourceUrl.trim()) {
  throw new Error('[ParseJDIHURL] source_url kosong: kolom PDF dan Url tidak ada di Google Sheet row ini.');
}

const slug  = rawUrl.split('/').pop().toLowerCase().trim();
const match = slug.match(SLUG_RE);

let docType, docNumber, docYear;

if (match) {
  docType   = TYPE_MAP[match[1]] || match[1].toUpperCase();
  docNumber = match[2];
  docYear   = match[3];
} else {
  const parts    = slug.split('-');
  const tahunIdx = parts.indexOf('tahun');
  docType   = TYPE_MAP[parts[0]] || parts[0].toUpperCase();
  docNumber = parts[1] || '';
  docYear   = tahunIdx !== -1 ? parts[tahunIdx + 1] : '';
}

return [{
  json: {
    docType,
    docNumber,
    docYear,
    fullQuery:       `${docType} ${docNumber} ${docYear}`.trim(),
    mengubah:        input.mengubah,
    diubah_oleh:     input.diubah_oleh,
    mencabut:        input.mencabut,
    dicabut_oleh:    input.dicabut_oleh,
    status_hukum:    input.status_hukum,
    riwayat_dokumen: input.riwayat_dokumen,
    jenis_pajak:     input.jenis_pajak,
    source_url:      resolvedSourceUrl,
  },
}];

const TYPE_TO_BENTUK = {
  UU:      'Undang-Undang',
  PMK:     'Peraturan Menteri',
  PP:      'Peraturan Pemerintah',
  PER:     'Peraturan Unit Eselon I',
  KMK:     'Keputusan Menteri',
  PERPRES: 'Peraturan Presiden',
};

const parsedDoc   = $('ParseJDIHURL').first().json;
const xtract    = $('ExtractPDF').first().json;
const { data: jdihData } = $input.first().json;

const targetType   = (parsedDoc.docType  || '').toUpperCase();
const targetNo     = String(parsedDoc.docNumber || '').trim();
const targetYear   = String(parsedDoc.docYear   || '').trim();
const targetBentuk = TYPE_TO_BENTUK[targetType];

if (!targetBentuk) {
  return [{ json: { jdih_found: false, reason: `Tipe dokumen ${targetType} tidak terdaftar di mapping.` } }];
}
if (!jdihData || jdihData.length === 0) {
  return [{ json: { jdih_found: false, reason: 'API JDIH memberikan respon kosong.' } }];
}

const exactMatch = jdihData.find(item =>
  String(item.bentuk).toLowerCase() === targetBentuk.toLowerCase()
  && String(item.no).trim()    === targetNo
  && String(item.tahun).trim() === targetYear
);

if (!exactMatch) {
  return [{
    json: {
      jdih_found: false,
      reason: `Dokumen ${targetBentuk} No ${targetNo} Tahun ${targetYear} tidak ditemukan di JDIH.`,
    },
  }];
}

// ── [V11] Parse Abstrak JDIH ──────────────────────────────────────────────────
let abstrak_raw    = null;
let doc_keywords   = null;
let doc_ringkasan  = null;
let dasar_hukum    = null;

const abstrakRaw = exactMatch.abstrak || exactMatch.abstract || null;

if (abstrakRaw && abstrakRaw.trim().length > 0) {
  abstrak_raw = abstrakRaw.trim();

  // 1. doc_keywords — baris pertama setelah header "ABSTRAK PERATURAN"
  //    Format: "COVID-19 – VAKSIN – VALUTA ASING" atau baris pertama abstrak
  const keywordMatch = abstrak_raw.match(/ABSTRAK\s+PERATURAN[^\n]*\n([^\n]+)/i);
  if (keywordMatch) {
    const rawKw = keywordMatch[1].trim();
    // Split by common separators: –, -, ;, •
    doc_keywords = rawKw.split(/[–\-;•,]+/).map(k => k.trim()).filter(k => k.length > 0);
  } else {
    // Fallback: baris pertama abstrak sebagai keywords
    const firstLine = abstrak_raw.split('\n')[0].trim();
    if (firstLine.length > 0 && firstLine.length < 300) {
      doc_keywords = firstLine.split(/[–\-;•,]+/).map(k => k.trim()).filter(k => k.length > 0);
    }
  }

  // 2. dasar_hukum — paragraf setelah "Dasar Hukum Peraturan ini adalah:"
  const dasarMatch = abstrak_raw.match(/Dasar Hukum[^:]*:\s*([\s\S]*?)(?=\n\n|\n[A-Z]|$)/i);
  if (dasarMatch) {
    const dasarText = dasarMatch[1].trim();
    // Split per peraturan: UU, PP, PMK, KMK, Perpres, dll
    dasar_hukum = dasarText
      .split(/[;\n]+/)
      .map(s => s.replace(/^\d+\.\s*/, '').trim())
      .filter(s => s.length > 3 && /UU|PP|PMK|KMK|Perpres|Peraturan|Undang|Keputusan/i.test(s));
    if (dasar_hukum.length === 0) dasar_hukum = null;
  }

  // 3. doc_ringkasan — paragraf "Dalam Peraturan ini diatur:"
  const ringkasanMatch = abstrak_raw.match(/Dalam\s+Peraturan(?:\s+(?:Menteri|ini))*\s+ini\s+diatur\s*:?\s*([\s\S]{10,})/i);
  if (ringkasanMatch) {
    doc_ringkasan = ringkasanMatch[1].trim().slice(0, 500);
  }
}
// ── End Parse Abstrak ─────────────────────────────────────────────────────────

return [{
  json: {
    jdih_found:           true,
    status_hukum:         exactMatch.status,
    doc_title:            exactMatch.judul,
    slug:                 exactMatch.slug,
    bentuk_jdih:          exactMatch.bentuk,
    tanggal_pengundangan: exactMatch.tanggal_pengundangan,
    doc_type:             targetType,
    doc_number:           targetNo,
    doc_year:             targetYear,
    jenis_pajak:          parsedDoc.jenis_pajak || 'Umum',
    source_url:           parsedDoc.source_url,
    riwayat_dokumen:      parsedDoc.riwayat_dokumen || null,
    is_consolidated:      exactMatch.konsolidasi === 1,
    matched_by:           'strict_string_logic',
    // [V11] Abstrak fields
    abstrak_raw:          abstrak_raw,
    doc_keywords:         doc_keywords,
    doc_ringkasan:        doc_ringkasan,
    dasar_hukum:          dasar_hukum,
  },
}];

// Node: "MergeBestSource"
// V11: Tambah pass-through field abstrak dari ParseJDIHResponse.

const jdih = $input.first().json;

// ── 1. AMBIL TEKS SECARA AMAN (Multi-Path Fallback) ──────────────────────────
let rawFullText = '';
let activeSource = 'UNKNOWN';

try {
  const htmlText = $('ExtractHTML').first().json.text;
  if (htmlText && htmlText.trim().length > 100) {
    rawFullText = htmlText;
    activeSource = 'JDIH_HTM';
  } else {
    throw new Error('HTML text terlalu pendek atau kosong');
  }
} catch (e) {
  try {
    const pdfText = $('ExtractPDF').first().json.text;
    if (pdfText && pdfText.trim().length > 100) {
      rawFullText = pdfText;
      activeSource = 'JDIH_PDF';
    } else {
      throw new Error('PDF text terlalu pendek atau kosong');
    }
  } catch (e2) {
    try {
      if (jdih.raw_full_text && jdih.raw_full_text.trim().length > 100) {
        rawFullText = jdih.raw_full_text;
        activeSource = 'JDIH_DIRECT';
      }
    } catch (e3) {
      // Semua jalur gagal
    }
  }
}

// ── 2. GUARD: Jika rawFullText kosong ────────────────────────────────────────
if (!rawFullText || rawFullText.trim().length === 0) {
  throw new Error(
    `[MergeBestSource] GAGAL: Tidak ada teks yang bisa diekstrak untuk ` +
    `${jdih.doc_type} ${jdih.doc_number}/${jdih.doc_year}. ` +
    `Semua jalur (ExtractHTML, ExtractPDF, raw_full_text) kosong.`
  );
}

// ── 3. PENYUSUNAN METADATA AKHIR ─────────────────────────────────────────────
const mergedMeta = {
  doc_type:          jdih.doc_type,
  doc_number:        jdih.doc_number,
  doc_year:          jdih.doc_year,
  doc_title:         jdih.doc_title,
  jenis_pajak:       jdih.jenis_pajak,
  status_hukum:      jdih.status_hukum,
  berlaku_sejak:     jdih.berlaku_sejak,
  dicabut_oleh:      jdih.dicabut_oleh      || null,
  doc_category:      'Umum',  // Parse Metadata1 akan override dengan validasi enum
  tgl_penetapan:     jdih.tgl_penetapan,
  tgl_pengundangan:  jdih.tgl_pengundangan,
  jdih_source_url:   jdih.jdih_source_url,
  nomor_lengkap:     jdih.nomor_lengkap,
  status_confidence: jdih.status_confidence,
  _data_source:      activeSource,
  riwayat_dokumen:   jdih.riwayat_dokumen,
  // [V11] Pass-through abstrak fields
  abstrak_raw:       jdih.abstrak_raw    || null,
  doc_keywords:      jdih.doc_keywords   || null,
  doc_ringkasan:     jdih.doc_ringkasan  || null,
  dasar_hukum:       jdih.dasar_hukum    || null,
};

// ── 4. OUTPUT FINAL ───────────────────────────────────────────────────────────
return [{
  json: {
    choices: [{
      message: {
        content: JSON.stringify({ metadata: mergedMeta })
      }
    }],
    raw_full_text: rawFullText,
    source_url:    jdih.source_url || jdih.jdih_source_url,
    jdih_found:    jdih.jdih_found
  }
}];

const BULAN_MAP = {
  jan: '01', feb: '02', mar: '03', apr: '04',
  mei: '05', jun: '06', jul: '07', agu: '08',
  sep: '09', okt: '10', nov: '11', des: '12',
};

const NOMOR_RE = /^(UU|PP|PMK|PER|KMK|SE|PERPPU|PERPU)\s+(?:NO\.?\s*|NOMOR\s+)?(\d+)(?:[\/\-][\w.]+)*\s+(?:TAHUN\s+)?(\d{4})$/i;
const DATE_RE  = /^(\d{1,2})\s+(\w+)\s+(\d{4})$/;
const TANGGAL_LINE_RE = /^(\d{1,2}\s+\w+\s+\d{4}):?$/;

function normalizeDate(raw) {
  if (!raw) return null;
  const m = raw.trim().match(DATE_RE);
  if (!m) return raw;
  const month = BULAN_MAP[m[2].toLowerCase().substring(0, 3)];
  return month ? `${m[3]}-${month}-${m[1].padStart(2, '0')}` : raw;
}

function parseNomor(raw) {
  const cleaned = (raw || '')
    .replace(/^(dengan|diubah(\s+oleh)?|mencabut|mengubah|sebagian)\s+/gi, '')
    .trim();
  const m = cleaned.match(NOMOR_RE);
  if (m) return { doc_type: m[1].toUpperCase(), doc_number: m[2], doc_year: m[3] };
  return { doc_type: null, doc_number: null, doc_year: null };
}

function buildEntry(nomor, judul, tanggal) {
  return { ...parseNomor(nomor), judul: (judul || '').trim(), tanggal: normalizeDate(tanggal) };
}

function parseRiwayat(text) {
  const result = { mencabut: [], diubah_oleh: [], mengubah: [] };
  let currentTanggal = null;

  for (const line of (text || '').split(/\r?\n/)) {
    const trimmed = line.trim();
    if (!trimmed) continue;

    const tanggalMatch = trimmed.match(TANGGAL_LINE_RE);
    if (tanggalMatch) { currentTanggal = tanggalMatch[1]; continue; }

    const mencabutMatch  = trimmed.match(/^Mencabut\s+(.+?)\s+tentang\s+(.+)$/i);
    if (mencabutMatch)  { result.mencabut.push(buildEntry(mencabutMatch[1], mencabutMatch[2], currentTanggal));  continue; }

    const diubahMatch    = trimmed.match(/^Diubah\s+(?:oleh\s+)?(.+?)\s+tentang\s+(.+)$/i);
    if (diubahMatch)    { result.diubah_oleh.push(buildEntry(diubahMatch[1], diubahMatch[2], currentTanggal));   continue; }

    const mengubahMatch  = trimmed.match(/^Mengubah\s+(.+?)\s+tentang\s+(.+)$/i);
    if (mengubahMatch)  { result.mengubah.push(buildEntry(mengubahMatch[1], mengubahMatch[2], currentTanggal)); }
  }
  return result;
}

const { metadata = {}, raw_full_text: rawFullText } = $input.first().json;
const parsed = parseRiwayat(metadata.riwayat_dokumen);

return [{
  json: {
    metadata: {
      ...metadata,
      mencabut:        parsed.mencabut,
      diubah_oleh:     parsed.diubah_oleh,
      mengubah:        parsed.mengubah,
      riwayat_dokumen: null,
    },
    raw_full_text: rawFullText,
  },
}];

const BLOCK_TAGS_RE    = /<\/(p|div|br|tr|h[1-4]|table)>/gi;
const HTML_TAG_RE      = /<[^>]+>/g;
const MULTI_SPACE_RE   = /[ \t]+/g;
const BLANK_LINES_RE   = /\n\s*\n/g;
const NUMERIC_ENT_RE   = /&#(\d+);/g;
const HEX_ENT_RE       = /&#x([0-9a-fA-F]+);/g;

const HTML_ENTITIES = {
  '&nbsp;':  ' ',  '&amp;':   '&',  '&lt;':  '<',  '&gt;':  '>',
  '&quot;':  '"',  '&apos;':  "'",  '&#39;': "'",
  '&ndash;': '–',  '&mdash;': '—',  '&hellip;': '…',
};

function decodeEntities(text) {
  return text
    .replace(/&[a-z]+;|&#39;/gi, m => HTML_ENTITIES[m] ?? m)
    .replace(NUMERIC_ENT_RE, (_, n) => String.fromCharCode(parseInt(n, 10)))
    .replace(HEX_ENT_RE,     (_, h) => String.fromCharCode(parseInt(h, 16)));
}

// Mengambil data HTML dari output node sebelumnya
const html = $input.first().json.data || '';

const text = decodeEntities(
  html
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(BLOCK_TAGS_RE, '\n')
    .replace(HTML_TAG_RE, ' ')
)
  .replace(/\r\n/g, '\n') // MENGHAPUS \r agar menjadi \n standar
  .replace(/\r/g, '\n')
  .replace(MULTI_SPACE_RE, ' ')
  .replace(BLANK_LINES_RE, '\n')
  .trim();

// Ambil metadata dari node JDIH awal untuk diteruskan ke bawah
const jdihData = $('GetAPIDataJDIH').first().json.data[0];

return [{ 
  json: { 
    raw_full_text: text,
    metadata: {
      doc_type: jdihData.bentuk,
      doc_id: jdihData.produk_hukum_id,
      doc_number: jdihData.nomor,
      doc_title: jdihData.judul,
      doc_year: jdihData.tahun,
      jenis_pajak:        jdihData.jenis_pajak || 'Umum',
      is_consolidated:    jdihData.konsolidasi === 1,

    // [V11] Abstrak fields
   // abstrak_raw:          abstrak_raw,
   // doc_keywords:         doc_keywords,
   // doc_ringkasan:        doc_ringkasan,
   // dasar_hukum:          dasar_hukum,
      status_hukum:  $('ParseJDIHURL').first().json.status_hukum,
    riwayat_dokumen: $('ParseJDIHURL').first().json.riwayat_dokumen || null,
    source_url: $('ParseJDIHURL').first().json.source_url
    }
  } 
}];

// Shared parsing utilities (mirrors ParseRiwayatDoc with additional PMK slash format)

const BULAN_MAP = {
  jan: '01', feb: '02', mar: '03', apr: '04',
  mei: '05', jun: '06', jul: '07', agu: '08',
  sep: '09', okt: '10', nov: '11', des: '12',
};

const DATE_RE         = /^(\d{1,2})\s+(\w+)\s+(\d{4})$/;
const TANGGAL_LINE_RE = /^(\d{1,2}\s+\w+\s+\d{4}):?$/;
const PMK_SLASH_RE    = /^([\d]+)\/(PMK|UU|PP|PER|KMK|SE)[\d.]*\/(\d{4})/i;
const STANDARD_NO_RE  = /(UU|PP|PMK|PER|KMK|SE|PERPPU)\s*(?:NO\.?\s*|NOMOR\s+)?([\d.\/]+)\s*(?:TAHUN\s+)?(\d{4})/i;
const CLEANUP_RE      = /^(dengan|diubah|oleh|mencabut|mengubah)\s+/gi;

function normalizeDate(raw) {
  if (!raw) return null;
  const m = raw.trim().match(DATE_RE);
  if (!m) return raw;
  const month = BULAN_MAP[m[2].toLowerCase().substring(0, 3)];
  return month ? `${m[3]}-${month}-${m[1].padStart(2, '0')}` : raw;
}

function parseNomor(raw) {
  const cleaned = (raw || '').replace(CLEANUP_RE, '').trim();

  const slash = cleaned.match(PMK_SLASH_RE);
  if (slash) {
    return { doc_type: slash[2].toUpperCase(), doc_number: slash[1], doc_year: slash[3], raw_nomor: cleaned };
  }

  const std = cleaned.match(STANDARD_NO_RE);
  if (std) {
    let num = std[2].replace(/\/$/, '');
    if (num.startsWith('.')) {
      const firstNum = cleaned.match(/^(\d+)/);
      if (firstNum) num = firstNum[1];
    }
    return { doc_type: std[1].toUpperCase(), doc_number: num, doc_year: std[3], raw_nomor: cleaned };
  }

  return { doc_type: null, doc_number: null, doc_year: null, raw_nomor: cleaned };
}

function buildEntry(nomor, judul, tanggal) {
  const cleanJudul = (judul || '')
    .split(/\d{1,2}\s+\w+\s+\d{4}/)[0]
    .replace(/^tentang\s+/i, '')
    .trim();
  return { ...parseNomor(nomor), judul: cleanJudul, tanggal: normalizeDate(tanggal) };
}

function parseRiwayat(text) {
  const result = { mencabut: [], diubah_oleh: [], mengubah: [] };
  let lastTanggal = null;

  for (const line of (text || '').split(/\r?\n/).map(l => l.trim()).filter(Boolean)) {
    const tanggalMatch = line.match(TANGGAL_LINE_RE);
    if (tanggalMatch) { lastTanggal = tanggalMatch[1]; continue; }

    let type = null;
    let content = null;
    if (/^Mengubah\s+/i.test(line))      { type = 'mengubah';  content = line.match(/^Mengubah\s+(.+?)\s+tentang\s+(.+)$/i); }
    else if (/^Diubah\s+/i.test(line))   { type = 'diubah_oleh'; content = line.match(/^Diubah\s+(?:oleh\s+)?(.+?)\s+tentang\s+(.+)$/i); }
    else if (/^Mencabut\s+/i.test(line)) { type = 'mencabut';  content = line.match(/^Mencabut\s+(.+?)\s+tentang\s+(.+)$/i); }

    if (type && content) {
      result[type].push(buildEntry(content[1], content[2], lastTanggal));
      lastTanggal = null;
    }
  }
  return result;
}

const raw        = $('ParseJDIHURL').first().json;
const resRiwayat = parseRiwayat(raw.riwayat_dokumen);
const resMengubah = parseRiwayat(raw.mengubah);

let dicabut_oleh = null;
if (raw.dicabut_oleh) {
  const m = raw.dicabut_oleh.match(/^(?:Dicabut\s+(?:dengan\s+)?)?(.+?)\s+tentang\s+(.+)$/i);
  dicabut_oleh = m
    ? buildEntry(m[1], m[2], raw.tanggal_pencabutan)
    : buildEntry(raw.dicabut_oleh, null, raw.tanggal_pencabutan);
}

return [{
  json: {
    source_url:   raw.source_url,
    status_hukum: raw.status_hukum || null,
    dicabut_oleh,
    diubah_oleh:  [...resRiwayat.diubah_oleh, ...resMengubah.diubah_oleh],
    mencabut:     [...resRiwayat.mencabut, ...resMengubah.mencabut],
    mengubah:     [...resRiwayat.mengubah, ...resMengubah.mengubah],
  },
}];

// ════════════════════════════════════════════════════════════════════════
// NODE: Central Metadata Hub (V14 - Compliance Pass-Through)
// Fungsi: Konsolidasi metadata dari API JDIH, PDF, HTML, URL, serta
//         meneruskan analitik anti-penghindaran pajak ke node Upsert.
//
// FIXES & UPGRADES:
// ✅ doc_type   — prioritas ParseJDIHURL (slug), bukan apiJdih.bentuk
// ✅ doc_number — prioritas ParseJDIHURL (slug), bukan apiJdih.nomor
// ✅ doc_year   — prioritas ParseJDIHURL (slug), bukan apiJdih.tahun
// ✅ rawFullText — prioritas PDF, HTML sebagai fallback
// ✅ [V14] Pass-through fields aman untuk Avoidance Signals & GAAR Exposure
// ════════════════════════════════════════════════════════════════════════

// --- 1. Helper Functions ---

function getSafeNodeData(nodeName) {
  try {
    const node = $(nodeName);
    return node && node.first() ? node.first().json : {};
  } catch (e) {
    return {};
  }
}

function inferJenisPajak(labels, current, title, docNumber) {
  if (current && current !== 'Umum') return current;

  const searchStr = [
    ...(Array.isArray(labels) ? labels : []),
    (title     || ""),
    (docNumber || "")
  ].join(' ').toUpperCase();

  const rules = [
    { pattern: /\bPPH\b|PAJAK PENGHASILAN/,          value: 'PPh'      },
    { pattern: /\bPPN\b|PERTAMBAHAN NILAI/,            value: 'PPN'      },
    { pattern: /\bKUP\b|KETENTUAN UMUM/,               value: 'KUP'      },
    { pattern: /\bCUKAI\b|BEA MASUK|BEA KELUAR/,      value: 'Bea_Cukai'},
    { pattern: /\bPBB\b|BUMI DAN BANGUNAN/,            value: 'PBB'      },
    { pattern: /\bPPNBM\b|PENJUALAN ATAS BARANG MEWAH/, value: 'PPnBM'  }
  ];

  const match = rules.find(r => r.pattern.test(searchStr));
  return match ? match.value : 'Umum';
}

// --- 2. Data Acquisition ---

const jdihUrl      = getSafeNodeData('ParseJDIHURL');
const jdihData     = getSafeNodeData('ParseJDIHResponse');
const extractPdf   = getSafeNodeData('ExtractPDF');
const extractHtml  = getSafeNodeData('ExtractHTML');
const apiJdihFull  = getSafeNodeData('GetAPIDataJDIH');

// [V14 Extractions] Menggunakan helper agar aman dari error runtime jika node kosong
const semanticAnalyzer = getSafeNodeData('Semantic Analyzer');
const domainScoring    = getSafeNodeData('Domain Scoring Engine');

const apiJdih = apiJdihFull?.data?.[0] || {};

// --- 3. Identitas Dokumen (Source of Truth: ParseJDIHURL) ---
//
// ParseJDIHURL mem-parse slug URL JDIH dengan TYPE_MAP yang sudah benar:
//   uu-7-tahun-2021      → docType="UU",  docNumber="7",  docYear="2021"
//   pmk-28-tahun-2026    → docType="PMK", docNumber="28", docYear="2026"
//
// apiJdih.bentuk = "Peraturan Menteri" → JANGAN dipakai untuk doc_type
// apiJdih.nomor  = "PMK 28 TAHUN 2026" → JANGAN dipakai untuk doc_number

const docType   = jdihUrl.docType   || jdihData.doc_type   || null;
const docNumber = jdihUrl.docNumber || jdihData.doc_number  || null;
const docYear   = jdihUrl.docYear   || jdihData.doc_year    || null;

// --- 4. Text Selection (Prioritas: PDF → HTML → kosong) ---
//
// PDF diprioritaskan karena jalur HTML tidak selalu dijalankan.
// Kalau kedua-duanya ada, PDF lebih reliable untuk dokumen hukum.

const rawFullText = (
  extractPdf.text  ||
  extractHtml.text ||
  ""
).trim();

if (!rawFullText || rawFullText.length < 100) {
  throw new Error(
    `[MetadataHub] GAGAL: Tidak ada teks yang bisa diekstrak untuk ` +
    `${docType} ${docNumber}/${docYear}. ` +
    `ExtractPDF.text="${(extractPdf.text || '').slice(0, 50)}", ` +
    `ExtractHTML.text="${(extractHtml.text || '').slice(0, 50)}"`
  );
}

// --- 5. Metadata Construction ---

const metadata = {

  // ── Identitas Primer ────────────────────────────────────────────────
  // Sumber: ParseJDIHURL (slug) — format selalu konsisten
  doc_id:     apiJdih.produk_hukum_id || jdihData.id || null,
  doc_type:   docType,    // "UU" | "PMK" | "PP" | "PER" | "KMK" | "SE"
  doc_number: docNumber,  // "7" | "28" dst — angka saja, bukan full label
  doc_year:   docYear,    // "2021" | "2026" dst

  // ── Judul & Abstrak ─────────────────────────────────────────────────
  // Sumber: API JDIH (lebih lengkap dan akurat)
  doc_title:   apiJdih.judul   || jdihData.doc_title  || extractPdf.title || "",
  abstrak_raw: apiJdih.abstrak || jdihData.abstrak_raw || null,
  doc_keywords: Array.isArray(apiJdih.label)
    ? apiJdih.label
    : (jdihData.doc_keywords || []),

  // ── Klasifikasi ─────────────────────────────────────────────────────
  jenis_pajak: inferJenisPajak(
    apiJdih.label,
    jdihUrl.jenis_pajak,    // dari Google Sheet (input user) — prioritas tertinggi
    apiJdih.judul,
    docNumber
  ),
  status_hukum: (
    apiJdih.status        ||
    jdihData.status_hukum ||
    jdihUrl.status_hukum  ||
    'BERLAKU'
  ).toUpperCase(),
  doc_category: 'Umum',

  // ── Relasi & Riwayat ────────────────────────────────────────────────
  riwayat_dokumen: jdihData.riwayat_dokumen || jdihUrl.riwayat_dokumen || null,
  mencabut:        jdihUrl.mencabut         || jdihData.mencabut        || [],
  diubah_oleh:      jdihUrl.diubah_oleh      || jdihData.diubah_oleh     || [],
  mengubah:        jdihUrl.mengubah         || jdihData.mengubah         || [],
  dicabut_oleh:    jdihUrl.dicabut_oleh     || jdihData.dicabut_oleh     || null,

  // ── Tanggal & URL ───────────────────────────────────────────────────
  tanggal_penetapan: apiJdih.tanggal_penetapan || jdihData.tanggal_penetapan || null,
  source_url:        jdihUrl.source_url         || jdihData.source_url        || null,

  // ── Flags ───────────────────────────────────────────────────────────
  is_consolidated: !!apiJdih.konsolidasi,
  _data_source:    extractPdf.text ? 'JDIH_PDF' : (extractHtml.text ? 'JDIH_HTM' : 'UNKNOWN'),
  processed_at:    new Date().toISOString(),

  // ── Debug (hapus setelah stable) ────────────────────────────────────
  _debug: {
    apiJdih_bentuk: apiJdih.bentuk || null,   // "Peraturan Menteri" — intentionally NOT used
    apiJdih_nomor:  apiJdih.nomor  || null,   // "PMK 28 TAHUN 2026" — intentionally NOT used
    slug_docType:   jdihUrl.docType   || null,
    slug_docNumber: jdihUrl.docNumber || null,
    text_source:    extractPdf.text ? 'PDF' : (extractHtml.text ? 'HTML' : 'NONE'),
    text_length:    rawFullText.length,
  }
};

// --- 6. Return Output ---

return [{
  json: {
    raw_full_text: rawFullText,
    metadata:      metadata,
    source_url:    metadata.source_url,

    // ── [V14] Avoidance fields — Pass-through dari Semantic Analyzer & Domain Scoring ──
    avoidance_signals:        semanticAnalyzer.avoidance_signals        || null,
    thresholds:               semanticAnalyzer.thresholds               || null,
    exception_refs:           semanticAnalyzer.exception_refs           || null,
    applicable_entity_types:  semanticAnalyzer.applicable_entity_types  || null,
    gaar_exposure_level:      domainScoring.gaar_exposure_level         || null,
  }
}];

// ════════════════════════════════════════════════════════════════════════
// METADATA ENRICHER — V4 MULTI-LABEL SEMANTIC TYPES
// FIX-2: semantic_type sekarang ARRAY (multi-label), bukan single string.
// Satu pasal bisa sekaligus 'obligation' + 'sanction' + 'timeline'.
// ════════════════════════════════════════════════════════════════════════

const items = $input.all();

// ───────────────────────────────────────────────────────────────────────
// REGEX
// ───────────────────────────────────────────────────────────────────────

const AYAT_RE          = /ayat\s*\((\d+)\)/gi;
const PASAL_REF_RE     = /Pasal\s+(\d+[A-Z]?)/gi;
const HURUF_RE         = /huruf\s+([a-z])/gi;

const DEFINISI_RE      = /yang\s+selanjutnya\s+disebut|yang\s+dimaksud\s+dengan|adalah/i;
const SANKSI_RE        = /dikenai\s+sanksi|sanksi\s+administratif|dipidana|pidana|denda/i;
const KEWAJIBAN_RE     = /\bwajib\b|\bharus\b|berkewajiban/i;
const LARANGAN_RE      = /\bdilarang\b|tidak\s+boleh/i;
const PENGECUALIAN_RE  = /dikecualikan|kecuali(?!\s+itu)|selain\s+(?:hal|dalam)/i;
const PROSEDUR_RE      = /permohonan|pengajuan|pelaporan|pendaftaran|penyampaian/i;
const BATAS_WAKTU_RE   = /paling\s+lambat|jangka\s+waktu|paling\s+lama|paling\s+singkat/i;

// ───────────────────────────────────────────────────────────────────────
// HELPERS
// ───────────────────────────────────────────────────────────────────────

function unique(arr) { return [...new Set(arr)]; }

function extractAyat(text) {
  const results = []; let m;
  while ((m = AYAT_RE.exec(text)) !== null) results.push(`ayat (${m[1]})`);
  return unique(results);
}

function extractPasalRefs(text, selfPasalNumber) {
  const results = []; let m;
  while ((m = PASAL_REF_RE.exec(text)) !== null) results.push(`Pasal ${m[1]}`);
  const all = unique(results);
  // FIX-B: buang self-reference (header pasal itu sendiri)
  return selfPasalNumber
    ? all.filter(ref => ref !== selfPasalNumber)
    : all;
}

function extractHuruf(text) {
  const results = []; let m;
  while ((m = HURUF_RE.exec(text)) !== null) results.push(`huruf ${m[1]}`);
  return unique(results);
}

// FIX-2: Multi-label — evaluasi SEMUA kondisi, hasilkan array.
// Tidak ada early return; setiap flag independen.
function detectSemanticTypes(text, pasalNumber) {
  const types = [];
  const lower = text.toLowerCase();

  // Definisi: Pasal 1 atau pola umum
  if (
    (pasalNumber === 'Pasal 1' && (lower.includes('adalah') || lower.includes('yang dimaksud'))) ||
    DEFINISI_RE.test(text)
  ) {
    types.push('definition');
  }

  if (SANKSI_RE.test(text))       types.push('sanction');
  if (LARANGAN_RE.test(text))     types.push('prohibition');
  if (KEWAJIBAN_RE.test(text))    types.push('obligation');
  if (PENGECUALIAN_RE.test(text)) types.push('exception');
  if (PROSEDUR_RE.test(text))     types.push('procedure');
  if (BATAS_WAKTU_RE.test(text))  types.push('timeline');

  return types.length > 0 ? unique(types) : ['general'];
}

// Boost dihitung dari semua tipe yang terdeteksi (kumulatif, max 2.0)
const BOOST_MAP = {
  definition:  0.25,
  sanction:    0.30,
  obligation:  0.20,
  prohibition: 0.20,
  exception:   0.15,
  timeline:    0.10,
};

function calculateRetrievalBoost(semanticTypes, text) {
  let boost = 1.0;
  for (const t of semanticTypes) {
    boost += (BOOST_MAP[t] || 0);
  }
  // Extra boost jika banyak referensi silang
  if (extractPasalRefs(text).length >= 3) boost += 0.10;
  return Number(Math.min(boost, 2.0).toFixed(2));
}

function generateMiniSummary(text) {
  const cleaned = text.replace(/\n+/g, ' ').replace(/\s+/g, ' ').trim();
  return cleaned.length <= 220 ? cleaned : cleaned.slice(0, 220) + '...';
}

// ───────────────────────────────────────────────────────────────────────
// MAIN
// ───────────────────────────────────────────────────────────────────────

return items.map(item => {
  const json = item.json;
  const text = json.chunk_text || '';

  const semanticTypes   = detectSemanticTypes(text, json.pasal_number);
  // FIX-B: pass pasal_number agar self-reference difilter
  const outgoingRefs    = extractPasalRefs(text, json.pasal_number);
  const ayatNumbers     = extractAyat(text);
  const hurufRefs       = extractHuruf(text);
  const retrievalBoost  = calculateRetrievalBoost(semanticTypes, text);

  // Untuk backward compat: semantic_type (string) = tipe prioritas tertinggi
  const PRIORITY_ORDER  = ['sanction','prohibition','obligation','definition','exception','procedure','timeline','general'];
  const primaryType     = PRIORITY_ORDER.find(t => semanticTypes.includes(t)) || semanticTypes[0];

  return {
    json: {
      ...json,

      // FIX-2: multi-label array (field baru)
      semantic_types:       semanticTypes,
      // backward compat: string untuk node downstream yang pakai semantic_type
      semantic_type:        primaryType,

      // Boolean flags — sekarang berdasarkan array
      contains_definition:  semanticTypes.includes('definition'),
      contains_sanction:    semanticTypes.includes('sanction'),
      contains_exception:   semanticTypes.includes('exception'),
      contains_obligation:  semanticTypes.includes('obligation'),
      contains_prohibition: semanticTypes.includes('prohibition'),
      contains_procedure:   semanticTypes.includes('procedure'),
      contains_timeline:    semanticTypes.includes('timeline'),

      outgoing_references:  outgoingRefs,
      ayat_numbers:         ayatNumbers,
      huruf_references:     hurufRefs,

      hierarchy_level:      'pasal_chunk',
      retrieval_boost:      retrievalBoost,
      chunk_summary:        generateMiniSummary(text),
      metadata_enriched_at: new Date().toISOString(),
    }
  };
});

// ════════════════════════════════════════════════════════════════════════
// SEMANTIC ANALYZER — V7 ENTERPRISE (COMPLIANCE & LEAK DETECTION)
//
// FIXES & UPGRADES:
// ✅ All V6 Fixes (Hierarchy-safe, Definition priority, Token estimation)
// ✅ V7 Added: Avoidance Signal Detector (Celah Hukum)
// ✅ V7 Added: Threshold Extractor (Rupiah, Persen, Hari, UMKM, DER)
// ✅ V7 Added: Applicable Entity Extractor (PT, CV, Perorangan, dll)
// ✅ Safe-guarding: Pencegahan error jika chunk_text kosong
// ════════════════════════════════════════════════════════════════════════

const items = $input.all();

// ════════════════════════════════════════
// HELPERS
// ════════════════════════════════════════

function hasAny(text='', patterns=[]) {
  return patterns.some(p => p.test(text));
}

function estimateTokens(text='') {
  return Math.ceil(text.length / 4);
}

// ════════════════════════════════════════
// NORMALIZE HIERARCHY
// ════════════════════════════════════════

function normalizeHierarchy(j) {
  // definition chunks MUST stay definition_item
  if (
    j.ast_type === 'DEFINITION' ||
    j.is_definition_chunk === true
  ) {
    return 'definition_item';
  }

  // ayat
  if (
    j.hierarchy_level === 'ayat'
  ) {
    return 'ayat';
  }

  // default
  return 'pasal_chunk';
}

// ════════════════════════════════════════
// TIMELINE DETECTOR
// ════════════════════════════════════════

function detectTimeline(text='') {
  const t = text.toLowerCase();
  const legalReferenceOnly =
    /undang-undang nomor\s+\d+\s+tahun\s+\d{4}/i.test(t);

  if (legalReferenceOnly) {
    const proceduralTimeline =
      hasAny(t, [
        /jangka waktu/i,
        /hari kerja/i,
        /dalam waktu/i,
        /paling lama/i,
        /terhitung sejak/i,
        /jatuh tempo/i,
        /sebelum tanggal/i,
        /setelah tanggal/i,
        /\d+\s+hari/i,
        /\d+\s+bulan/i
      ]);

    return proceduralTimeline;
  }

  return hasAny(t, [
    /jangka waktu/i,
    /hari kerja/i,
    /dalam waktu/i,
    /paling lama/i,
    /terhitung sejak/i,
    /jatuh tempo/i,
    /sebelum tanggal/i,
    /setelah tanggal/i,
    /\d+\s+hari/i,
    /\d+\s+bulan/i,
    /\d+\s+tahun pajak/i
  ]);
}

// ════════════════════════════════════════
// SEMANTIC ANALYZER
// ════════════════════════════════════════

function analyzeSemantic(j) {
  const text = (j.chunk_text || '').toLowerCase();
  const semanticTypes = [];
  const isDefinition =
    j.ast_type === 'DEFINITION' ||
    j.is_definition_chunk === true;

  // DEFINITIONS HAVE PRIORITY
  if (isDefinition) {
    semanticTypes.push('definition');
    return semanticTypes;
  }

  // obligation
  if (
    hasAny(text, [
      /wajib/i,
      /harus/i
    ])
  ) {
    semanticTypes.push('obligation');
  }

  // prohibition
  if (
    hasAny(text, [
      /dilarang/i,
      /tidak boleh/i
    ])
  ) {
    semanticTypes.push('prohibition');
  }

  // sanction
  if (
    hasAny(text, [
      /sanksi/i,
      /pidana/i,
      /denda/i
    ])
  ) {
    semanticTypes.push('sanction');
  }

  // procedure
  if (
    hasAny(text, [
      /permohonan/i,
      /pengajuan/i,
      /ditetapkan/i,
      /menerbitkan/i
    ])
  ) {
    semanticTypes.push('procedure');
  }

  // exception
  if (
    hasAny(text, [
      /dikecualikan/i,
      /kecuali/i
    ])
  ) {
    semanticTypes.push('exception');
  }

  // timeline
  if (
    detectTimeline(text)
  ) {
    semanticTypes.push('timeline');
  }

  return semanticTypes;
}

// ════════════════════════════════════════
// AVOIDANCE SIGNAL DETECTOR (V7 Upgrade)
// Deteksi pola celah hukum pada teks pasal
// ════════════════════════════════════════

function detectAvoidanceSignals(text) {
  const t = text.toLowerCase();
  const signals = {};

  // --- Threshold Arbitrage ---
  const thresholdPatterns = [
    /paling tinggi\s+rp[\s.]*([\d.,]+)/gi,
    /tidak melebihi\s+rp[\s.]*([\d.,]+)/gi,
    /paling banyak\s+rp[\s.]*([\d.,]+)/gi,
    /kurang dari\s+rp[\s.]*([\d.,]+)/gi,
    /tidak lebih dari\s+rp[\s.]*([\d.,]+)/gi,
    /sampai dengan\s+rp[\s.]*([\d.,]+)/gi,
    /omzet[\s\w]*tidak melebihi/gi,
    /peredaran bruto[\s\w]*tidak melebihi/gi,
    /\b4[\.,]8\s*miliar\b/gi,
    /\b4\.800\.000\.000\b/gi,
  ];
  signals.threshold_arbitrage = thresholdPatterns.some(p => p.test(t));

  // --- Exception Clause ---
  const exceptionPatterns = [
    /dikecualikan dari/gi,
    /tidak dikenakan/gi,
    /tidak termasuk/gi,
    /sepanjang memenuhi/gi,
    /dengan syarat/gi,
    /kecuali[\s\w]*yang/gi,
    /tidak berlaku bagi/gi,
    /dibebaskan dari/gi,
    /mendapat fasilitas/gi,
    /tidak dikenai pajak/gi,
    /bukan objek pajak/gi,
  ];
  signals.exception_clause = exceptionPatterns.some(p => p.test(t));

  // --- Entity Type Exception ---
  const entityPatterns = [
    /badan usaha milik negara/gi,
    /\bbumn\b/gi,
    /usaha mikro/gi,
    /usaha kecil/gi,
    /koperasi[\s\w]*yang/gi,
    /yayasan[\s\w]*yang/gi,
    /wajib pajak badan/gi,
    /orang pribadi/gi,
    /wajib pajak luar negeri/gi,
    /bentuk usaha tetap/gi,
    /\bbut\b/gi,
  ];
  signals.entity_type_exception = entityPatterns.some(p => p.test(t));

  // --- Timing Window ---
  const timingPatterns = [
    /masa transisi/gi,
    /berlaku sampai dengan/gi,
    /paling lama[\s\w]*tahun/gi,
    /dalam jangka waktu[\s\w]*tahun/gi,
    /sebelum[\s\w]*berlaku/gi,
    /mulai berlaku pada/gi,
    /sejak[\s\w]*diundangkan/gi,
    /ketentuan lama/gi,
  ];
  signals.timing_window = timingPatterns.some(p => p.test(t));

  // --- Cross Border Gap ---
  const crossBorderPatterns = [
    /perjanjian penghindaran pajak berganda/gi,
    /\bp3b\b/gi,
    /tax treaty/gi,
    /luar negeri/gi,
    /bersumber dari luar negeri/gi,
    /hubungan istimewa/gi,
    /transfer pricing/gi,
    /harga transfer/gi,
    /deemed dividend/gi,
    /controlled foreign/gi,
    /\bcfc\b/gi,
  ];
  signals.cross_border_gap = crossBorderPatterns.some(p => p.test(t));

  // --- Rate Differential ---
  const ratePatterns = [
    /tarif[\s\w]*lebih rendah/gi,
    /tarif[\s\w]*\d+%/gi,
    /tarif final/gi,
    /dikenakan tarif/gi,
    /0%|nol persen/gi,
    /tarif khusus/gi,
    /tarif pajak ditanggung pemerintah/gi,
    /\bdtp\b/gi,
  ];
  signals.rate_differential = ratePatterns.some(p => p.test(t));

  const hasAnySignal = Object.values(signals).some(v => v === true);
  return hasAnySignal ? signals : null;
}

// ════════════════════════════════════════
// THRESHOLD EXTRACTOR (V7 Upgrade)
// Ekstrak angka threshold aktual dari teks
// ════════════════════════════════════════

function extractThresholds(text) {
  const thresholds = {};

  // Ekstrak nilai Rupiah
  const rupiahRe = /(?:rp\.?\s*|rupiah\s*)([\d.,]+(?:\s*(?:juta|miliar|triliun))?)/gi;
  const rupiahMatches = [...text.matchAll(rupiahRe)];
  if (rupiahMatches.length > 0) {
    thresholds.nilai_rupiah = rupiahMatches.map(m => m[0].trim()).slice(0, 5);
  }

  // Ekstrak persentase tarif
  const pctRe = /(\d+(?:[.,]\d+)?)\s*%/g;
  const pctMatches = [...text.matchAll(pctRe)];
  if (pctMatches.length > 0) {
    thresholds.tarif_persen = [...new Set(pctMatches.map(m => parseFloat(m[1])))].slice(0, 5);
  }

  // Ekstrak batas hari
  const hariRe = /(\d+)\s*hari(?:\s*kerja)?/gi;
  const hariMatches = [...text.matchAll(hariRe)];
  if (hariMatches.length > 0) {
    thresholds.batas_hari = hariMatches.map(m => parseInt(m[1])).slice(0, 3);
  }

  // Flag PP 23/2018 UMKM secara khusus
  if (/4[\.,]8\s*miliar|4\.800\.000\.000/.test(text)) {
    thresholds.umkm_threshold = 4800000000;
  }

  // Flag thin cap DER 4:1
  if (/4\s*:\s*1|debt.{1,20}equity\s*ratio/i.test(text)) {
    thresholds.der_max = 4;
  }

  return Object.keys(thresholds).length > 0 ? thresholds : null;
}

// ════════════════════════════════════════
// APPLICABLE ENTITY EXTRACTOR (V7 Upgrade)
// Tentukan jenis entitas yang relevan
// ════════════════════════════════════════

function extractApplicableEntities(text) {
  const t = text.toUpperCase();
  const entities = [];

  if (/\bPT\b|PERSEROAN TERBATAS/.test(t)) entities.push('PT');
  if (/\bCV\b|COMMANDITAIRE VENNOOTSCHAP|PERSEKUTUAN KOMANDITER/.test(t)) entities.push('CV');
  if (/USAHA DAGANG|PERUSAHAAN PERSEORANGAN/.test(t)) entities.push('UD');
  if (/ORANG PRIBADI|WAJIB PAJAK ORANG/.test(t)) entities.push('Perorangan');
  if (/BENTUK USAHA TETAP|\bBUT\b/.test(t)) entities.push('BUT');
  if (/KOPERASI/.test(t)) entities.push('Koperasi');
  if (/YAYASAN/.test(t)) entities.push('Yayasan');
  if (/BADAN USAHA MILIK NEGARA|\bBUMN\b/.test(t)) entities.push('BUMN');
  if (/USAHA MIKRO|USAHA KECIL|USAHA MENENGAH|\bUMKM\b/.test(t)) entities.push('UMKM');

  return entities.length > 0 ? entities : ['SEMUA'];
}

// ════════════════════════════════════════
// MAIN EXECUTOR
// ════════════════════════════════════════

return items.map(item => {
  const j = item.json;
  const chunkText = j.chunk_text || '';

  // 1. Jalankan modul analisa semantic lama (V6)
  const semanticTypes = analyzeSemantic(j);
  const semanticType = semanticTypes[0] || 'general';
  const normalizedHierarchy = normalizeHierarchy(j);

  // 2. Hitung retrieval boost (V6)
  let retrievalBoost = 1.0;
  if (semanticTypes.includes('definition')) retrievalBoost += 0.7;
  if (semanticTypes.includes('sanction'))   retrievalBoost += 0.5;
  if (semanticTypes.includes('procedure'))  retrievalBoost += 0.4;

  // 3. Ekstrak entitas hukum reguler (V6)
  const legalEntities = chunkText.match(/Undang-Undang Nomor\s+\d+\s+Tahun\s+\d{4}/gi) || [];

  // 4. Integrasi Analitik Celah Hukum Baru (V7)
  const avoidanceSignals     = detectAvoidanceSignals(chunkText);
  const thresholds           = extractThresholds(chunkText);
  const applicableEntityTypes = extractApplicableEntities(chunkText);

  // 5. Kembalikan gabungan payload utuh
  return {
    json: {
      ...j,

      // Metadata Hierarki & Klasifikasi Utama (V6)
      hierarchy_level: normalizedHierarchy,
      semantic_types: semanticTypes,
      semantic_type: semanticType,

      // Flags Boolean Semantic (V6)
      contains_definition: semanticTypes.includes('definition'),
      contains_sanction: semanticTypes.includes('sanction'),
      contains_exception: semanticTypes.includes('exception'),
      contains_obligation: semanticTypes.includes('obligation'),
      contains_prohibition: semanticTypes.includes('prohibition'),
      contains_procedure: semanticTypes.includes('procedure'),
      contains_timeline: semanticTypes.includes('timeline'),

      // Pembobotan Vector Search (V6)
      retrieval_boost: retrievalBoost,
      semantic_importance: retrievalBoost,
      legal_entities: legalEntities,
      semantic_token_estimate: estimateTokens(chunkText),

      // Data Ekstraksi Celah Hukum Baru (V7)
      avoidance_signals: avoidanceSignals,
      thresholds: thresholds,
      applicable_entity_types: applicableEntityTypes,

      // Versioning & Timestamp
      semantic_analyzer_version: 'v7_compliance_leak_detection',
      semantic_analyzed_at: new Date().toISOString()
    }
  };
});

// ═══════════════════════════════════════════════════════════════
// Domain Scoring Engine — V3 (Advanced Tax Domains & GAAR Upgrade)
// For n8n Code Node
// ═══════════════════════════════════════════════════════════════

const items = $input.all();

// ───────────────────────────────────────────────────────────────
// DOMAIN PATTERNS (V3 Extended)
// ───────────────────────────────────────────────────────────────
const DOMAIN_PATTERNS = {

  PPh: [
    /Pajak Penghasilan/gi,
    /\bPPh\b/gi,
    /Pasal\s+21/gi,
    /Pasal\s+22/gi,
    /Pasal\s+23/gi,
    /Pasal\s+25/gi,
    /Pasal\s+26/gi,
    /Pasal\s+29/gi,
  ],

  PPN: [
    /Pajak Pertambahan Nilai/gi,
    /\bPPN\b/gi,
  ],

  PPnBM: [
    /\bPPnBM\b/gi,
    /Pajak Penjualan atas Barang Mewah/gi,
  ],

  "Bea Meterai": [
    /Bea Meterai/gi,
  ],

  PBB: [
    /Pajak Bumi dan Bangunan/gi,
    /\bPBB\b/gi,
  ],

  KUP: [
    /Ketentuan Umum dan Tata Cara Perpajakan/gi,
    /\bKUP\b/gi,
  ],

  Cukai: [
    /Cukai/gi,
  ],

  "Pajak Karbon": [
    /Pajak Karbon/gi,
  ],

  // --- Tambahan Domain Baru V3 ---
  TRANSFER_PRICING: [
    /transfer pricing/gi,
    /harga transfer/gi,
    /hubungan istimewa/gi,
    /arm.{1,5}length/gi,
    /prinsip kewajaran/gi,
    /dokumen transfer pricing/gi,
    /country.{1,10}country reporting/gi,
    /\bcbcr\b/gi,
    /advance pricing agreement/gi,
    /\bapa\b/gi,
  ],

  P3B: [
    /perjanjian penghindaran pajak berganda/gi,
    /\bp3b\b/gi,
    /tax treaty/gi,
    /bentuk usaha tetap/gi,
    /\bbut\b/gi,
    /controlled foreign corporation/gi,
    /\bcfc\b/gi,
    /deemed dividend/gi,
  ],

  GAAR: [
    /ketentuan anti penghindaran/gi,
    /general anti.avoidance/gi,
    /\bgaar\b/gi,
    /substansi ekonomi/gi,
    /economic substance/gi,
    /rekarakterisasi/gi,
    /penyalahgunaan perjanjian/gi,
    /treaty abuse/gi,
    /pasal 18/gi,
  ],

  TAX_FACILITY: [
    /fasilitas pajak/gi,
    /tax holiday/gi,
    /pembebasan pajak/gi,
    /pengurangan pajak/gi,
    /insentif pajak/gi,
    /kawasan ekonomi khusus/gi,
    /\bkek\b/gi,
    /kawasan berikat/gi,
    /\bkib\b/gi,
    /kemudahan investasi/gi,
  ]
};

// ───────────────────────────────────────────────────────────────
// HELPERS
// ───────────────────────────────────────────────────────────────
function countMatches(text, regex) {
  const matches = text.match(regex);
  return matches ? matches.length : 0;
}

function detectDomainScores(text) {
  const scores = {};

  for (const [domain, patterns] of Object.entries(DOMAIN_PATTERNS)) {
    let score = 0;
    for (const pattern of patterns) {
      score += countMatches(text, pattern);
    }
    scores[domain] = score;
  }

  return scores;
}

// ───────────────────────────────────────────────────────────────
// PRIMARY DOMAIN
// ───────────────────────────────────────────────────────────────
function getPrimaryDomain(scores) {
  const sorted = Object.entries(scores)
    .filter(([_, score]) => score > 0)
    .sort((a, b) => b[1] - a[1]);

  if (!sorted.length) {
    return 'UMUM';
  }

  // Hanya MULTI_DOMAIN jika benar-benar identik
  if (
    sorted.length > 1 &&
    sorted[0][1] === sorted[1][1]
  ) {
    return 'MULTI_DOMAIN';
  }

  return sorted[0][0];
}

// ───────────────────────────────────────────────────────────────
// SECONDARY DOMAINS
// ───────────────────────────────────────────────────────────────
function getSecondaryDomains(scores, primary) {
  return Object.entries(scores)
    .filter(([domain, score]) =>
      score > 0 &&
      domain !== primary
    )
    .map(([domain]) => domain);
}

// ───────────────────────────────────────────────────────────────
// CONFIDENCE
// ───────────────────────────────────────────────────────────────
function calculateConfidence(scores) {
  const values = Object.values(scores)
    .filter(v => v > 0)
    .sort((a, b) => b - a);

  if (values.length === 0) return 0;
  if (values.length === 1) return 1;

  const top = values[0];
  const second = values[1];

  return Number(
    (top / (top + second)).toFixed(2)
  );
}

// ───────────────────────────────────────────────────────────────
// RISK ASSESSMENT HELPER (V3 Upgrade)
// ───────────────────────────────────────────────────────────────
function assessGaarExposure(j) {
  const signals = j.avoidance_signals || {};
  const domain  = j.primary_domain || '';

  // Exposure tinggi jika menyentuh GAAR/TP domain atau cross-border
  if (
    domain === 'GAAR' ||
    domain === 'TRANSFER_PRICING' ||
    signals.cross_border_gap === true
  ) return 'HIGH';

  // Exposure sedang jika ada exception/timing/rate game
  if (
    signals.exception_clause === true ||
    signals.timing_window === true ||
    signals.rate_differential === true
  ) return 'MEDIUM';

  // Exposure rendah jika hanya threshold biasa
  if (signals.threshold_arbitrage === true) return 'LOW';

  return null;
}

// ───────────────────────────────────────────────────────────────
// EXECUTION
// ───────────────────────────────────────────────────────────────
return items.map(item => {
  const json = item.json;

  // Gabungkan semua text semantic
  const text = `
${json.chunk_text || ''}
${json.chunk_summary || ''}
${(json.legal_concept_tags || []).join(' ')}
${json.doc_title || ''}
`;

  // 1. Hitung Domain Score
  const domainScores = detectDomainScores(text);

  // 2. Tentukan Primary Domain
  const primaryDomain = getPrimaryDomain(domainScores);

  // 3. Tentukan Secondary Domains
  const secondaryDomains = getSecondaryDomains(domainScores, primaryDomain);

  // 4. Ekstrak Semua Domain Tags aktif
  const domainTags = Object.entries(domainScores)
    .filter(([_, score]) => score > 0)
    .map(([domain]) => domain);

  // 5. Hitung Tingkat Confidence
  const confidence = calculateConfidence(domainScores);

  // 6. Evaluasi GAAR Exposure Level (Menggunakan data pendukung dari payload json)
  const gaarExposureLevel = assessGaarExposure({
    avoidance_signals: json.avoidance_signals,
    primary_domain: primaryDomain
  });

  // 7. Kembalikan Payload Akhir
  return {
    json: {
      ...json,
      domain_scores: domainScores,
      primary_domain: primaryDomain,
      secondary_domains: secondaryDomains,
      domain_tags: domainTags,
      domain_confidence: confidence,
      gaar_exposure_level: gaarExposureLevel, // Field baru V3
      domain_scored_at: new Date().toISOString(),
    }
  };
});

const failedChunks = [];

for (const item of items) {

  const data = item.json;

  failedChunks.push({
    failed_at: new Date().toISOString(),

    relational_id: data.relational_id || null,
    pasal_number: data.pasal_number || null,

    quality_score: data.quality_score || 0,

    quality_flags: data.quality_flags || [],

    primary_domain: data.primary_domain || null,

    chunk_preview: (data.chunk_text || "")
      .substring(0, 300),

    total_characters: (data.chunk_text || "").length
  });
}

return failedChunks.map(x => ({
  json: x
}));

// ════════════════════════════════════════════════════════════════════════
// QUALITY GATE — V2
// FIX-4: Tambah flag INCOMPLETE_ARTICLE untuk mendeteksi pasal terpotong.
//        Scoring disesuaikan dengan multi-label semantic_types.
// ════════════════════════════════════════════════════════════════════════

const results = [];

// Pola akhiran pasal yang lengkap secara hukum
const VALID_ENDINGS_RE  = /[.;]\s*$/;
// Header pasal (indikasi ada judul tapi konten bisa terpotong)
const PASAL_HEADER_RE   = /^#{1,3}\s+Pasal\s+\d+[A-Z]?/m;
// Ayat atau huruf di akhir chunk (tanda masih ada lanjutan)
const DANGLING_LIST_RE  = /\b(?:huruf|angka)\s+[a-z]\s*[;:]?\s*$/i;

function isIncompleteArticle(text) {
  // Heuristik 1: ada header Pasal tapi tidak diakhiri tanda baca lengkap
  if (PASAL_HEADER_RE.test(text) && !VALID_ENDINGS_RE.test(text)) return true;
  // Heuristik 2: chunk berakhir dengan daftar menggantung (huruf a; huruf b:)
  if (DANGLING_LIST_RE.test(text)) return true;
  // Heuristik 3: chunk dimulai di tengah kalimat (sudah ada BROKEN_START tapi
  // kita juga cek jika tidak ada header sama sekali untuk chunk panjang)
  if (text.length > 300 && !PASAL_HEADER_RE.test(text) && !VALID_ENDINGS_RE.test(text)) return true;
  return false;
}

for (const item of items) {
  const data = item.json;
  const text = (data.chunk_text || '').trim();

  // ─── BASIC METRICS ───────────────────────────────────────────────────
  const textLength = text.length;
  const wordCount  = text.split(/\s+/).length;

  // ─── QUALITY FLAGS ───────────────────────────────────────────────────
  const qualityFlags = [];

  if (textLength < 120)  qualityFlags.push('TOO_SHORT');
  if (wordCount < 20)    qualityFlags.push('LOW_WORD_COUNT');

  if (
    text.startsWith('.') || text.startsWith(',') ||
    text.startsWith(')') || text.startsWith('dan ') ||
    text.startsWith('atau ')
  ) qualityFlags.push('BROKEN_START');

  if (!data.primary_domain)  qualityFlags.push('MISSING_DOMAIN');
  if (!data.semantic_type)   qualityFlags.push('MISSING_SEMANTIC_TYPE');

  // FIX-4: Deteksi pasal terpotong
  if (isIncompleteArticle(text)) qualityFlags.push('INCOMPLETE_ARTICLE');

  // ─── QUALITY SCORE ────────────────────────────────────────────────────
  let qualityScore = 1.0;
  qualityScore -= qualityFlags.length * 0.15;

  // Bonus dari multi-label semantic_types
  const sTypes = data.semantic_types || [];
  if (sTypes.includes('definition'))  qualityScore += 0.05;
  if (sTypes.includes('sanction'))    qualityScore += 0.10;
  if ((data.semantic_importance || 1) > 1.3) qualityScore += 0.05;

  // Penalty ekstra untuk pasal terpotong (konten tidak dapat dipercaya sepenuhnya)
  if (qualityFlags.includes('INCOMPLETE_ARTICLE')) qualityScore -= 0.10;

  qualityScore = Math.max(0, Math.min(1, Number(qualityScore.toFixed(2))));

  // ─── EMBEDDING ELIGIBILITY ────────────────────────────────────────────
  // INCOMPLETE_ARTICLE tidak otomatis blokir embedding (data parsial masih berguna)
  // tapi threshold lebih ketat jika ada flag tersebut.
  const criticalFlags  = qualityFlags.filter(f => f !== 'INCOMPLETE_ARTICLE');
  const embeddingReady =
    criticalFlags.length <= 1 &&
    qualityScore >= (qualityFlags.includes('INCOMPLETE_ARTICLE') ? 0.65 : 0.55);

  results.push({
    json: {
      ...data,
      quality_flags:       qualityFlags,
      quality_score:       qualityScore,
      embedding_ready:     embeddingReady,
      quality_checked_at:  new Date().toISOString(),
    }
  });
}

return results;

// ═══════════════════════════════════════════════════════════════
// EMBEDDING BUILDER ENGINE — V14 ENTERPRISE
// For n8n Code Node (Central Vector Preparation)
// ═══════════════════════════════════════════════════════════════

const items = $input.all();

// ───────────────────────────────────────────────────────────────
// HELPERS & NORMALIZERS
// ───────────────────────────────────────────────────────────────

function normalizeTerm(term) {
  if (!term) return "";

  return term
    .toLowerCase()
    .replace(/[^\w\s-]/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function uniqueArray(arr) {
  return [...new Set(arr.filter(Boolean))];
}

function buildAliases(term) {
  if (!term) return [];

  const aliases = [];
  const upper = term.toUpperCase();

  // =========================
  // KUP
  // =========================
  if (upper.includes("KETENTUAN UMUM DAN TATA CARA PERPAJAKAN")) {
    aliases.push("UU KUP");
    aliases.push("KUP");
    aliases.push("Ketentuan Umum Perpajakan");
  }

  // =========================
  // PPN
  // =========================
  if (upper.includes("PAJAK PERTAMBAHAN NILAI")) {
    aliases.push("UU PPN");
    aliases.push("PPN");
  }

  // =========================
  // PKP
  // =========================
  if (upper.includes("PENGUSAHA KENA PAJAK")) {
    aliases.push("PKP");
  }

  // =========================
  // NPWP
  // =========================
  if (upper.includes("NOMOR POKOK WAJIB PAJAK")) {
    aliases.push("NPWP");
  }

  // =========================
  // SKPKB
  // =========================
  if (upper.includes("SURAT KETETAPAN PAJAK KURANG BAYAR")) {
    aliases.push("SKPKB");
  }

  // =========================
  // STP
  // =========================
  if (upper.includes("SURAT TAGIHAN PAJAK")) {
    aliases.push("STP");
  }

  return uniqueArray(aliases);
}

function buildChunkHeadline(chunk) {
  const term =
    chunk.definition_term ||
    chunk.pasal_title ||
    "Dokumen Hukum";

  return `Definisi ${term} dalam ${chunk.doc_number || ""} Pasal ${chunk.pasal_number || ""}`;
}

function buildCitationShort(chunk) {
  return `${chunk.doc_number || ""} Pasal ${chunk.pasal_number || ""} Definisi ${chunk.definition_number || ""}`;
}

function buildCitationPath(chunk) {
  const hierarchy = Array.isArray(chunk.hierarchy_path)
    ? chunk.hierarchy_path.join(" > ")
    : "";

  return `${chunk.doc_number || ""} > ${hierarchy}`;
}

// ───────────────────────────────────────────────────────────────
// VECTOR READY TEXT (V14 UPGRADE - INJECT AVOIDANCE SIGNALS)
// ───────────────────────────────────────────────────────────────

function buildVectorReadyText(chunk, aliases) {
  const sections = [];

  if (chunk.definition_term) {
    sections.push(chunk.definition_term);
  }

  if (aliases.length) {
    sections.push(aliases.join("\n"));
  }

  if (chunk.doc_number) {
    sections.push(chunk.doc_number);
  }

  if (chunk.doc_title) {
    sections.push(chunk.doc_title);
  }

  if (chunk.chunk_text) {
    sections.push(chunk.chunk_text);
  }

  // [V14] Tambahkan sinyal avoidance ke embedding text
  if (chunk.avoidance_signals) {
    const signalLabels = Object.entries(chunk.avoidance_signals)
      .filter(([_, v]) => v === true)
      .map(([k]) => k.replace(/_/g, ' '))
      .join(', ');

    if (signalLabels) {
      sections.push(`Celah pajak: ${signalLabels}`);
    }
  }

  if (chunk.applicable_entity_types && chunk.applicable_entity_types[0] !== 'SEMUA') {
    sections.push(`Berlaku untuk: ${chunk.applicable_entity_types.join(', ')}`);
  }

  if (chunk.thresholds) {
    const thr = JSON.stringify(chunk.thresholds);
    sections.push(`Threshold: ${thr}`);
  }

  return sections.join("\n\n").trim();
}

function buildSearchText(chunk, aliases) {
  const parts = [];

  if (chunk.definition_term) {
    parts.push(chunk.definition_term);
  }

  aliases.forEach(a => parts.push(a));

  if (chunk.doc_number) {
    parts.push(chunk.doc_number);
  }

  if (chunk.doc_title) {
    parts.push(chunk.doc_title);
  }

  if (chunk.chunk_text) {
    parts.push(chunk.chunk_text);
  }

  return parts.join(" ").replace(/\s+/g, " ").trim();
}

function buildEmbeddingInput(chunk, aliases) {
  const lines = [];

  lines.push(
    `Definisi ${chunk.definition_term || ""} dalam ${chunk.doc_number || ""} Pasal ${chunk.pasal_number || ""}.`
  );

  if (aliases.length) {
    lines.push(`Alias: ${aliases.join(", ")}`);
  }

  if (chunk.doc_title) {
    lines.push(`Dokumen: ${chunk.doc_title}`);
  }

  if (chunk.chunk_text) {
    lines.push(`Isi:\n${chunk.chunk_text}`);
  }

  return lines.join("\n\n").trim();
}

// ───────────────────────────────────────────────────────────────
// MAIN EXECUTOR
// ───────────────────────────────────────────────────────────────

return items.map(item => {
  const chunk = item.json;

  // =========================
  // ALIAS
  // =========================
  const aliases = buildAliases(chunk.definition_term || "");

  // =========================
  // NORMALIZED TERMS
  // =========================
  const normalizedTerms = uniqueArray([
    normalizeTerm(chunk.definition_term || ""),
    ...aliases.map(a => normalizeTerm(a))
  ]);

  // =========================
  // HEADLINE & CITATIONS
  // =========================
  chunk.chunk_headline = buildChunkHeadline(chunk);
  chunk.citation_short = buildCitationShort(chunk);
  chunk.citation_path  = buildCitationPath(chunk);

  // =========================
  // ALIAS & TERMS STORAGE
  // =========================
  chunk.canonical_aliases = aliases;
  chunk.normalized_terms   = normalizedTerms;

  // =========================
  // VECTOR READY TEXT (V14 Enhanced)
  // =========================
  const vectorReadyText = buildVectorReadyText(chunk, aliases);
  chunk.vector_ready_text = vectorReadyText;
  chunk.retrieval_text    = vectorReadyText; // Sinkronisasi dengan retrieval text

  // =========================
  // BM25 SEARCH TEXT & EMBEDDING INPUT
  // =========================
  chunk.search_text     = buildSearchText(chunk, aliases);
  chunk.embedding_input = buildEmbeddingInput(chunk, aliases);

  // =========================
  // STATIC METADATA FIXED FIELDS
  // =========================
  chunk.entity_type = "legal_definition";
  chunk.effective_status = chunk.status_hukum === "BERLAKU" ? "active" : "inactive";

  // =========================
  // DOCUMENT FAMILY
  // =========================
  if (!chunk.document_family) {
    if (chunk.doc_number && chunk.doc_number.includes("PMK")) {
      chunk.document_family = "PMK";
    } else if (chunk.doc_number && chunk.doc_number.includes("PER")) {
      chunk.document_family = "PER";
    } else {
      chunk.document_family = "UNKNOWN";
    }
  }

  // =========================
  // LEGAL DOMAIN & YEAR
  // =========================
  if (!chunk.legal_domain) {
    chunk.legal_domain = "perpajakan";
  }

  if (!chunk.effective_year) {
    chunk.effective_year = chunk.doc_year || null;
  }

  // =========================
  // PRIORITY ALGORITHM
  // =========================
  if (!chunk.search_priority) {
    let priority = 50;

    if (chunk.is_definition_chunk)  priority += 25;
    if (chunk.contains_obligation)    priority += 10;
    if (chunk.contains_sanction)      priority += 15;

    chunk.search_priority = priority;
  }

  // =========================
  // CHUNK TYPE PRIORITY
  // =========================
  if (!chunk.chunk_type_priority) {
    if (chunk.semantic_type === "definition") {
      chunk.chunk_type_priority = 7;
    } else if (chunk.semantic_type === "procedure") {
      chunk.chunk_type_priority = 8;
    } else {
      chunk.chunk_type_priority = 5;
    }
  }

  // =========================
  // VERSIONING & TIMESTAMP
  // =========================
  chunk.embedding_builder_version = "vFinal_legal_rag_enterprise";
  chunk.embedding_built_at        = new Date().toISOString();

  return item;
});

const crypto = require('crypto');

return $input.all().map(item => {

  const text =
    item.json.chunk_text;

  const hash =
    crypto
      .createHash('sha256')
      .update(text)
      .digest('hex');

  return {
    json: {
      ...item.json,
      chunk_hash: hash
    }
  };
});

// ════════════════════════════════════════════════════════════════════════
// EMBEDDING QUALITY VALIDATOR — V3
// Refactor Upgrade
//
// Features:
// ✅ relational_id pairing
// ✅ dimension validation
// ✅ L2 norm validation
// ✅ NaN detection
// ✅ Infinity detection
// ✅ variance detection
// ✅ contextual embedding validation
// ✅ embedding fingerprint preview
// ✅ embedding version tagging
// ════════════════════════════════════════════════════════════════════════

const EXPECTED_DIM = 1536;

const MIN_L2_NORM = 0.1;

const MIN_VARIANCE = 1e-6;

const EMBEDDING_MODEL = 'text-embedding-3-small';

const EMBEDDING_PIPELINE_VERSION = 'v3';

// ════════════════════════════════════════
// LOAD QUALITY GATE ITEMS
// ════════════════════════════════════════

const qualityGateItems = $('Quality check?').all();

const qualityMap = {};

for (const q of qualityGateItems) {

  const rid = q.json.relational_id;

  if (rid) {
    qualityMap[rid] = q.json;
  }
}

// ════════════════════════════════════════
// VALIDATION FUNCTIONS
// ════════════════════════════════════════

function validateEmbedding(vec, chunkId) {

  // NULL / TYPE CHECK

  if (!vec || !Array.isArray(vec)) {
    throw new Error(
      `[EmbeddingValidator] Embedding null/bukan array pada chunk: ${chunkId}`
    );
  }

  // DIMENSION CHECK

  if (vec.length !== EXPECTED_DIM) {
    throw new Error(
      `[EmbeddingValidator] Dimensi salah: expected ${EXPECTED_DIM}, got ${vec.length} (Chunk: ${chunkId})`
    );
  }

  // NaN CHECK

  if (vec.some(v => Number.isNaN(v))) {
    throw new Error(
      `[EmbeddingValidator] NaN detected pada chunk: ${chunkId}`
    );
  }

  // INFINITY CHECK

  if (vec.some(v => !Number.isFinite(v))) {
    throw new Error(
      `[EmbeddingValidator] Infinite value detected pada chunk: ${chunkId}`
    );
  }

  // L2 NORM CHECK

  const l2 = Math.sqrt(
    vec.reduce((s, v) => s + v * v, 0)
  );

  if (l2 < MIN_L2_NORM) {
    throw new Error(
      `[EmbeddingValidator] L2 norm terlalu kecil (${l2.toFixed(6)}) pada chunk: ${chunkId}`
    );
  }

  // VARIANCE CHECK

  const mean =
    vec.reduce((a, b) => a + b, 0) / vec.length;

  const variance =
    vec.reduce(
      (s, v) => s + Math.pow(v - mean, 2),
      0
    ) / vec.length;

  if (variance < MIN_VARIANCE) {
    throw new Error(
      `[EmbeddingValidator] Variance terlalu kecil (${variance}) pada chunk: ${chunkId}`
    );
  }

  // FINGERPRINT PREVIEW
  // untuk duplicate detection ringan

  const fingerprint =
    vec
      .slice(0, 24)
      .map(v => v.toFixed(4))
      .join('|');

  return {
    l2,
    variance,
    fingerprint
  };
}

// ════════════════════════════════════════
// MAIN PROCESSING
// ════════════════════════════════════════

const items = $input.all();

return items.map((item, index) => {

  const embeddingResponse = item.json;

  const embedding =
    embeddingResponse.data?.[0]?.embedding;

  // ════════════════════════════════════
  // RELATIONAL PAIRING
  // ════════════════════════════════════

  const rid =
    embeddingResponse.relational_id ||
    embeddingResponse.input;

  const chunkData =
    (rid && qualityMap[rid])
      ? qualityMap[rid]
      : (qualityGateItems[index]?.json || {});

  const chunkId =
    chunkData.relational_id ||
    chunkData.chunk_index ||
    index;

  // ════════════════════════════════════
  // CONTEXTUAL EMBEDDING VALIDATION
  // ════════════════════════════════════

  if (!chunkData.embedding_input) {
    throw new Error(
      `[EmbeddingValidator] Missing embedding_input pada chunk: ${chunkId}`
    );
  }

  // ════════════════════════════════════
  // VALIDATE EMBEDDING
  // ════════════════════════════════════

  const validation =
    validateEmbedding(embedding, chunkId);

  // ════════════════════════════════════
  // OUTPUT
  // ════════════════════════════════════

  return {
    json: {

      ...chunkData,

      embedding_validated: true,

      embedding_vector: embedding,

      embedding_str:
        `[${embedding.join(',')}]`,

      l2_norm:
        Math.round(validation.l2 * 1_000_000) / 1_000_000,

      embedding_variance:
        validation.variance,

      embedding_fingerprint:
        validation.fingerprint,

      embedding_dimension:
        EXPECTED_DIM,

      embedding_model:
        EMBEDDING_MODEL,

      embedding_pipeline_version:
        EMBEDDING_PIPELINE_VERSION,

      embedding_validated_at:
        new Date().toISOString()
    }
  };
});

// ════════════════════════════════════════════════════════════════
// ADAPTIVE TOKEN CHUNKER — V6
// ENTERPRISE LEGAL HIERARCHY CHUNKER
//
// FEATURES:
// ✅ preserve metadata
// ✅ preserve hierarchy
// ✅ preserve AST semantics
// ✅ parent-child relation
// ✅ hierarchy path
// ✅ structural depth
// ✅ globally unique relational_id
// ✅ adaptive chunk splitting
// ✅ definition-aware chunking
// ✅ citation-ready architecture
// ✅ graph-ready architecture
//
// OUTPUT:
// optimized legal retrieval chunks
// ════════════════════════════════════════════════════════════════

const items = $input.all();

// ════════════════════════════════════════
// CONFIG
// ════════════════════════════════════════

const TARGET_TOKENS = 350;
const HARD_LIMIT = 500;

// ════════════════════════════════════════
// TOKEN ESTIMATOR
// ════════════════════════════════════════

function estimateTokens(text = '') {

  return Math.ceil(
    text.length / 4
  );
}

// ════════════════════════════════════════
// LEGAL PARAGRAPH SPLITTER
// ════════════════════════════════════════

function splitLegalParagraphs(text = '') {

  return text
    .split(/\n(?=\d+\.\s)|\n(?=[a-z]\.\s)/g)
    .map(s => s.trim())
    .filter(Boolean);
}

// ════════════════════════════════════════
// ADAPTIVE SPLITTER
// ════════════════════════════════════════

function adaptiveSplit(text = '') {

  const paragraphs =
    splitLegalParagraphs(text);

  const chunks = [];

  let current = '';

  for (const para of paragraphs) {

    const candidate =
      current
        ? current + '\n' + para
        : para;

    if (
      estimateTokens(candidate)
      <= TARGET_TOKENS
    ) {

      current = candidate;
      continue;
    }

    if (current) {
      chunks.push(current.trim());
    }

    // oversized paragraph
    if (
      estimateTokens(para)
      > HARD_LIMIT
    ) {

      const sentences =
        para.split(/(?<=\.)\s+/);

      let temp = '';

      for (const s of sentences) {

        const sentenceCandidate =
          temp
            ? temp + ' ' + s
            : s;

        if (
          estimateTokens(sentenceCandidate)
          <= TARGET_TOKENS
        ) {

          temp = sentenceCandidate;

        } else {

          if (temp) {
            chunks.push(temp.trim());
          }

          temp = s;
        }
      }

      if (temp) {
        chunks.push(temp.trim());
      }

      current = '';

      continue;
    }

    current = para;
  }

  if (current) {
    chunks.push(current.trim());
  }

  return chunks;
}

// ════════════════════════════════════════
// METADATA BUILDER
// ════════════════════════════════════════

function buildMetadata(j) {

  return {

    // identity
    doc_id:
      j.doc_id || null,

    doc_type:
      j.doc_type || null,

    doc_number:
      j.doc_number || null,

    doc_year:
      j.doc_year || null,

    doc_title:
      j.doc_title || null,

    doc_category:
      j.doc_category || null,

    source_url:
      j.source_url || null,

    document_slug:
      j.document_slug || null,

    // enrichment
    doc_keywords:
      j.doc_keywords || [],

    status_hukum:
      j.status_hukum || null,

    jenis_pajak:
      j.jenis_pajak || null,

    tanggal_penetapan:
      j.tanggal_penetapan || null,

    // hierarchy
    bab:
      j.bab || null,

    pasal_number:
      j.pasal_number || null,

    pasal_title:
      j.pasal_title || null,

    hierarchy_level:
      j.hierarchy_level || null,

    ast_type:
      j.ast_type || null,

    semantic_label:
      j.semantic_label || null,

    definition_term:
      j.definition_term || null,

    definition_number:
      j.definition_number || null,

    ast_version:
      j.ast_version || null
  };
}

// ════════════════════════════════════════
// BUILD HIERARCHY PATH
// ════════════════════════════════════════

function buildHierarchyPath(j) {

  const path = [];

  if (j.bab) {
    path.push(j.bab);
  }

  if (j.pasal_title) {
    path.push(j.pasal_title);
  }

  if (j.definition_number) {
    path.push(
      `Definisi ${j.definition_number}`
    );
  }

  return path;
}

// ════════════════════════════════════════
// MAIN EXECUTION
// ════════════════════════════════════════

const output = [];

let globalChunkIndex = 1;

for (const item of items) {

  const j = item.json;

  const text =
    j.raw_content || '';

  if (!text) continue;

  const metadata =
    buildMetadata(j);

  const hierarchyPath =
    buildHierarchyPath(j);

  const isDefinitionChunk =
    j.ast_type === 'DEFINITION'
    || j.hierarchy_level === 'definition_item';

  // ════════════════════════════════
  // DEFINITION CHUNKS
  // ════════════════════════════════

  if (isDefinitionChunk) {

    output.push({
      json: {

        ...metadata,

        hierarchy_level:
          'definition_item',

        hierarchy_path:
          hierarchyPath,

        structural_depth:
          hierarchyPath.length,

        parent_relation: {

          type:
            'pasal',

          id:
            `${j.document_slug}_pasal_${j.pasal_number}`
        },

        chunk_text:
          text,

        chunk_token_estimate:
          estimateTokens(text),

        chunk_index:
          globalChunkIndex++,

        semantic_boundary:
          'ast_definition_boundary',

        is_definition_chunk:
          true,

        relational_id:
          j.relational_id,

        chunker_version:
          'v6'
      }
    });

    continue;
  }

  // ════════════════════════════════
  // SHORT PASAL
  // ════════════════════════════════

  const totalTokens =
    estimateTokens(text);

  if (
    totalTokens <= TARGET_TOKENS
  ) {

    output.push({
      json: {

        ...metadata,

        hierarchy_level:
          'pasal_chunk',

        hierarchy_path:
          hierarchyPath,

        structural_depth:
          hierarchyPath.length,

        parent_relation: {

          type:
            'document',

          id:
            j.document_slug
        },

        chunk_text:
          text,

        chunk_token_estimate:
          totalTokens,

        chunk_index:
          globalChunkIndex++,

        semantic_boundary:
          'passthrough',

        is_definition_chunk:
          false,

        relational_id:
          `${j.relational_id}_chunk_1`,

        chunker_version:
          'v6'
      }
    });

    continue;
  }

  // ════════════════════════════════
  // ADAPTIVE SPLIT
  // ════════════════════════════════

  const chunks =
    adaptiveSplit(text);

  chunks.forEach((chunk, idx) => {

    output.push({
      json: {

        ...metadata,

        hierarchy_level:
          'pasal_chunk',

        hierarchy_path:
          hierarchyPath,

        structural_depth:
          hierarchyPath.length,

        parent_relation: {

          type:
            'pasal',

          id:
            j.relational_id
        },

        chunk_text:
          chunk,

        chunk_token_estimate:
          estimateTokens(chunk),

        chunk_index:
          globalChunkIndex++,

        semantic_boundary:
          'adaptive_split',

        is_definition_chunk:
          false,

        relational_id:
          `${j.relational_id}_chunk_${idx + 1}`,

        chunker_version:
          'v6'
      }
    });
  });
}

// ════════════════════════════════════════
// FINAL OUTPUT
// ════════════════════════════════════════

return output;

// ════════════════════════════════════════════════════════════════════════
// LEGAL AST PARSER — V6
// ENTERPRISE LEGAL INGESTION PARSER
//
// FIXES:
// ✅ metadata propagation FIXED
// ✅ globally unique relational_id
// ✅ document identity support
// ✅ OCR wrap normalization
// ✅ definition splitting
// ✅ heading leakage prevention
// ✅ lightweight architecture
// ✅ semantic hierarchy preservation
//
// RESULT:
// production-grade legal AST chunks
// ════════════════════════════════════════════════════════════════════════

const items = $input.all();

// ════════════════════════════════════════
// METADATA PICKER
// FIX: metadata now read from item.json.metadata
// ════════════════════════════════════════

function pickMetadata(j) {

  const meta =
    j.metadata || {};

  return {

    doc_id:
      meta.doc_id || null,

    doc_type:
      meta.doc_type || null,

    doc_number:
      meta.doc_number || null,

    doc_year:
      meta.doc_year || null,

    doc_title:
      meta.doc_title || null,

    doc_category:
      meta.doc_category || null,

    source_url:
      meta.source_url || null,

    doc_keywords:
      meta.doc_keywords || [],

    status_hukum:
      meta.status_hukum || null,

    jenis_pajak:
      meta.jenis_pajak || null,

    tanggal_penetapan:
      meta.tanggal_penetapan || null
  };
}

// ════════════════════════════════════════
// BUILD DOCUMENT SLUG
// ════════════════════════════════════════

function buildDocumentSlug(meta={}) {

  const type =
    (meta.doc_type || 'doc')
      .toString()
      .toLowerCase()
      .replace(/[^\w\s]/g, '')
      .replace(/\s+/g, '_');

  const number =
    (meta.doc_number || 'unknown')
      .toString()
      .toLowerCase()
      .replace(/[^\w\s]/g, '')
      .replace(/\s+/g, '_');

  const year =
    (meta.doc_year || 'unknown')
      .toString();

  return `${type}_${number}_${year}`;
}

// ════════════════════════════════════════
// DETECT UPPERCASE HEADINGS
// ════════════════════════════════════════

function isUppercaseHeading(line='') {

  const clean =
    line.trim();

  if (clean.length < 20) {
    return false;
  }

  // ignore numbered definitions
  if (/^\d+\./.test(clean)) {
    return false;
  }

  const upper =
    clean.replace(/[^A-Z]/g, '').length;

  const alpha =
    clean.replace(/[^A-Za-z]/g, '').length;

  if (!alpha) return false;

  return (upper / alpha) > 0.9;
}

// ════════════════════════════════════════
// NORMALIZE OCR WRAPS
// ════════════════════════════════════════

function normalizeLegalText(text='') {

  return text

    // normalize line endings
    .replace(/\r/g, '\n')

    // merge broken OCR words
    .replace(/([a-zA-Z])-\n([a-zA-Z])/g, '$1$2')

    // merge wrapped sentences
    .replace(/([a-zA-Z0-9,])\n([a-zA-Z])/g, '$1 $2')

    // preserve numbered list
    .replace(/(\.)\s+(\d+\.)/g, '$1\n$2')

    // preserve huruf list
    .replace(/([;:])\s+([a-z]\.)/g, '$1\n$2')

    // normalize spaces
    .replace(/[ \t]+/g, ' ')

    // normalize empty lines
    .replace(/\n{3,}/g, '\n\n')

    // trim lines
    .replace(/[ \t]+$/gm, '')

    .trim();
}

// ════════════════════════════════════════
// SPLIT DEFINITIONS
// ════════════════════════════════════════

function splitDefinitions(content='') {

  const lines =
    content.split('\n');

  const defs = [];

  let current = null;

  for (const raw of lines) {

    const line =
      raw.trim();

    if (!line) continue;

    const match =
      line.match(/^(\d+)\.\s+(.+)/);

    // new definition item
    if (match) {

      if (current) {
        defs.push(current);
      }

      current = {

        number:
          match[1],

        text:
          match[2]
      };

      continue;
    }

    // continuation line
    if (current) {

      current.text +=
        ' ' + line;
    }
  }

  if (current) {
    defs.push(current);
  }

  return defs;
}

// ════════════════════════════════════════
// EXTRACT LEGAL HIERARCHY
// ════════════════════════════════════════

function extractHierarchy(text='') {

  const lines =
    text.split('\n');

  let currentBAB = null;

  let currentPasal = null;

  const ast = [];

  for (const rawLine of lines) {

    const line =
      rawLine.trim();

    if (!line) continue;

    // ════════════════════════════════
    // BAB
    // ════════════════════════════════

    const babMatch =
      line.match(/^BAB\s+([IVXLCDM]+)/i);

    if (babMatch) {

      currentBAB = line;

      continue;
    }

    // ════════════════════════════════
    // PASAL
    // ════════════════════════════════

    const pasalMatch =
      line.match(/^Pasal\s+(\d+[A-Z]?)/i);

    if (pasalMatch) {

      currentPasal = {

        bab:
          currentBAB,

        pasal:
          pasalMatch[1],

        title:
          line,

        content: []
      };

      ast.push(currentPasal);

      continue;
    }

    // ════════════════════════════════
    // PREVENT HEADING LEAKAGE
    // ════════════════════════════════

    if (
      isUppercaseHeading(line)
    ) {
      continue;
    }

    // ════════════════════════════════
    // APPEND CONTENT
    // ════════════════════════════════

    if (currentPasal) {

      currentPasal.content.push(line);
    }
  }

  return ast;
}

// ════════════════════════════════════════
// MAIN EXECUTION
// ════════════════════════════════════════

const output = [];

for (const item of items) {

  const text =
    item.json.cleaned_text || '';

  if (!text) continue;

  // ════════════════════════════════
  // METADATA
  // ════════════════════════════════

  const metadata =
    pickMetadata(item.json);

  // ════════════════════════════════
  // DOCUMENT SLUG
  // ════════════════════════════════

  const documentSlug =
    buildDocumentSlug(metadata);

  // ════════════════════════════════
  // EXTRACT AST
  // ════════════════════════════════

  const ast =
    extractHierarchy(text);

  for (const node of ast) {

    const rawContent =
      normalizeLegalText(
        node.content.join('\n')
      );

    // skip empty
    if (!rawContent) {
      continue;
    }

    // ════════════════════════════════
    // DETECT DEFINITION PASAL
    // ════════════════════════════════

    const isDefinitionPasal =
      /yang dimaksud dengan/i.test(rawContent);

    // ════════════════════════════════
    // DEFINITION CHUNKS
    // ════════════════════════════════

    if (isDefinitionPasal) {

      const definitions =
        splitDefinitions(rawContent);

      definitions.forEach((def, idx) => {

        const definitionTerm =
          (
            def.text.split(' adalah ')[0] || ''
          )
          .replace(/\s+/g, ' ')
          .trim();

        output.push({
          json: {

            // metadata
            ...metadata,

            document_slug:
              documentSlug,

            // hierarchy
            bab:
              node.bab,

            pasal_number:
              node.pasal,

            pasal_title:
              node.title,

            hierarchy_level:
              'definition_item',

            ast_type:
              'DEFINITION',

            semantic_label:
              'definition',

            // definition metadata
            definition_number:
              def.number,

            definition_term:
              definitionTerm,

            // content
            raw_content:
              def.text,

            // indexing
            chunk_index:
              idx + 1,

            relational_id:
              `${documentSlug}_pasal_${node.pasal}_def_${def.number}`,

            ast_version:
              'v6'
          }
        });
      });

      continue;
    }

    // ════════════════════════════════
    // NORMAL PASAL
    // ════════════════════════════════

    output.push({
      json: {

        // metadata
        ...metadata,

        document_slug:
          documentSlug,

        // hierarchy
        bab:
          node.bab,

        pasal_number:
          node.pasal,

        pasal_title:
          node.title,

        hierarchy_level:
          'pasal',

        ast_type:
          'PASAL',

        semantic_label:
          'pasal',

        // content
        raw_content:
          rawContent,

        // indexing
        chunk_index:
          1,

        relational_id:
          `${documentSlug}_pasal_${node.pasal}`,

        ast_version:
          'v6'
      }
    });
  }
}

// ════════════════════════════════════════
// FINAL OUTPUT
// ════════════════════════════════════════

return output;

